+            1,
+            size,
+            PaneConstraints {
+                min_width: 10,
+                min_height: 3,
+                ..PaneConstraints::default()
+            },
+        ));
+        let split = tab
+            .compute_split_size(
+                0,
+                SplitRequest {
+                    direction: SplitDirection::Horizontal,
+                    ..Default::default()
+                },
+            )
+            .unwrap();
