+            0,
+            SplitRequest {
+                direction: SplitDirection::Horizontal,
+                ..Default::default()
+            },
+            FakePane::new_with_constraints(
+                2,
+                split.second,
+                PaneConstraints {
+                    min_width: 10,
+                    min_height: 3,
+                    ..PaneConstraints::default()
+                },
+            ),
+        )
+        .unwrap();
+
+        let budget = tab.compute_split_budget(0);
+        assert!(budget.is_some(), "split 0 should exist");
